arguments.file_text:
@* Vertical sidebar navigation for settings sections *@

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    <span class="section-icon">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.settings-sidebar {
    background-color: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
    min-width: 220px;
    height: 100%;
}

.sidebar-title {
    padding: 0 1.25rem;
    margin-bottom: 1rem;
    font-weight: 600;
    color: #495057;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.65rem 1.25rem;
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: all 0.15s ease;
}

.settings-sidebar .nav-link:hover {
    background-color: #e9ecef;
    color: #212529;
}

.settings-sidebar .nav-link.active {
    background-color: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.section-icon {
    font-size: 1.1rem;
}

@* Expandable change-password panel *@

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center"
         role="button" @onclick="ToggleExpanded">
        <span>🔑 Change Password</span>
        <span class="expand-icon">@(IsExpanded ? "▲" : "▼")</span>
    </div>

    @if (IsExpanded)
    {
        <div class="card-body">
            @if (!string.IsNullOrEmpty(message))
            {
                <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                    @message
                    <button type="button" class="btn-close" @onclick="() => message = null"></button>
                </div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="confirmPassword" />
            </div>
            <button class="btn btn-primary" @onclick="HandleChangePassword" disabled="@isSaving">
                @(isSaving ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool IsExpanded;
    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private string? message;
    private bool isError;
    private bool isSaving;

    private void ToggleExpanded() => IsExpanded = !IsExpanded;

    private async Task HandleChangePassword()
    {
        message = null;

        if (string.IsNullOrWhiteSpace(currentPassword) || string.IsNullOrWhiteSpace(newPassword))
        {
            message = "All password fields are required.";
            isError = true;
            return;
        }

        if (newPassword != confirmPassword)
        {
            message = "New password and confirmation do not match.";
            isError = true;
            return;
        }

        isSaving = true;
        try
        {
            await OnChangePassword.InvokeAsync((currentPassword, newPassword));
            message = "Password updated successfully.";
            isError = false;
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch (Exception ex)
        {
            message = $"Failed to update password: {ex.Message}";
            isError = true;
        }
        finally
        {
            isSaving = false;
        }
    }
}

.expand-icon {
    font-size: 0.75rem;
    color: #6c757d;
}

@* Confirmation dialog for revoking a session *@

@if (Visible)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal d-block fade show" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@Device</strong> from <strong>@Location</strong>?</p>
                    <p class="text-muted small">This will sign out that device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="Confirm">Revoke Session</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public string Device { get; set; } = "";
    [Parameter] public string Location { get; set; } = "";
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task Confirm() => await OnConfirm.InvokeAsync();
    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@* Vertical sidebar navigation for settings sections *@

<nav class="settings-sidebar">
