@using sv_770ddc18e887459eaf936bfe8a8135ab.Services
@inject ISettingsService SettingsService

<div class="section-panel">
    <h4 class="section-heading">Profile</h4>

    @if (isLoading)
    {
        <div class="text-center py-4"><div class="spinner-border text-primary" role="status"></div></div>
    }
    else
    {
        @if (statusMessage is not null)
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @statusMessage
                <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label">Display Name</label>
                    <input type="text" class="form-control" @bind="displayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email</label>
                    <input type="email" class="form-control" @bind="email" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Bio</label>
                    <textarea class="form-control" rows="4" @bind="bio"></textarea>
                </div>
            </div>
            <div class="col-md-4">
                <div class="avatar-preview text-center">
                    <img src="@avatarUrl" alt="Avatar" class="avatar-img rounded-circle mb-2" />
                    <div class="mb-2">
                        <label class="form-label small text-muted">Avatar URL</label>
                        <input type="text" class="form-control form-control-sm" @bind="avatarUrl" />
                    </div>
                </div>
            </div>
        </div>

        <div class="d-flex gap-2 mt-3">
            <button class="btn btn-primary" @onclick="SaveChanges" disabled="@isSaving">
                @(isSaving ? "Saving…" : "Save Changes")
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardChanges">
                Discard Changes
            </button>
        </div>
    }
</div>

@code {
    private string displayName = "";
    private string email = "";
    private string bio = "";
    private string avatarUrl = "";

    private UserProfile? savedProfile;
    private bool isLoading = true;
    private bool isSaving;
    private string? statusMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfile();
    }

    private async Task LoadProfile()
    {
        isLoading = true;
        savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(savedProfile);
        isLoading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        displayName = profile.DisplayName;
        email = profile.Email;
        bio = profile.Bio;
        avatarUrl = profile.AvatarUrl;
    }

    private async Task SaveChanges()
    {
        isSaving = true;
        var updated = new UserProfile(displayName, email, avatarUrl, bio);
        await SettingsService.SaveProfileAsync(updated);
        savedProfile = updated;
        statusMessage = "Profile saved successfully!";
        isSaving = false;
    }

    private void DiscardChanges()
    {
        if (savedProfile is not null)
        {
            ApplyProfile(savedProfile);
        }
        statusMessage = null;
    }
}

