@using sv_770ddc18e887459eaf936bfe8a8135ab.Services
@inject ISettingsService SettingsService

<div class="section-panel">
    <h4 class="section-heading">Appearance</h4>

    @if (isLoading)
    {
        <div class="text-center py-4"><div class="spinner-border text-primary" role="status"></div></div>
    }
    else
    {
        @if (statusMessage is not null)
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @statusMessage
                <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-7">
                <div class="card mb-3">
                    <div class="card-header">Theme</div>
                    <div class="card-body">
                        @foreach (var t in themes)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="@($"theme-{t}")" value="@t"
                                       checked="@(theme == t)"
                                       @onchange="() => theme = t" />
                                <label class="form-check-label" for="@($"theme-{t}")">@t</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="card mb-3">
                    <div class="card-header">Font Size</div>
                    <div class="card-body">
                        @foreach (var fs in fontSizes)
                        {
                            <div class="form-check form-check-inline">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="@($"fs-{fs}")" value="@fs"
                                       checked="@(fontSize == fs)"
                                       @onchange="() => fontSize = fs" />
                                <label class="form-check-label" for="@($"fs-{fs}")">@fs</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="card mb-3">
                    <div class="card-body">
                        <label class="form-label"><strong>Language</strong></label>
                        <select class="form-select" @bind="language">
                            @foreach (var lang in languages)
                            {
                                <option value="@lang">@lang</option>
                            }
                        </select>
                    </div>
                </div>

                <div class="card mb-3">
                    <div class="card-body">
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" id="compactMode" @bind="compactMode" />
                            <label class="form-check-label" for="compactMode">
                                <strong>Compact Mode</strong>
                                <div class="text-muted small">Reduce spacing and padding throughout the interface</div>
                            </label>
                        </div>
                    </div>
                </div>
            </div>

            <div class="col-md-5">
                <div class="card">
                    <div class="card-header">Live Preview</div>
                    <div class="card-body preview-area @GetPreviewClasses()">
                        <h5 style="@GetPreviewFontStyle()">Sample Heading</h5>
                        <p style="@GetPreviewFontStyle()">
                            This is a preview of how your content will look with the selected appearance settings.
                        </p>
                        <div class="d-flex gap-2 mt-2">
                            <button class="btn btn-sm btn-primary">Primary</button>
                            <button class="btn btn-sm btn-outline-secondary">Secondary</button>
                        </div>
                        <div class="mt-2 small text-muted" style="@GetPreviewFontStyle()">
                            Theme: @theme · Font: @fontSize · Language: @language · Compact: @(compactMode ? "On" : "Off")
                        </div>
                    </div>
                </div>
            </div>
        </div>

        <button class="btn btn-primary mt-2" @onclick="SaveAppearance" disabled="@isSaving">
            @(isSaving ? "Saving…" : "Save")
        </button>
    }
</div>

@code {
    private string theme = "Light";
    private string fontSize = "Medium";
    private string language = "English";
    private bool compactMode;

    private static readonly string[] themes = ["Light", "Dark", "System"];
    private static readonly string[] fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    private bool isLoading = true;
    private bool isSaving;
    private string? statusMessage;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        theme = settings.Theme;
        fontSize = settings.FontSize;
        language = settings.Language;
        compactMode = settings.CompactMode;
        isLoading = false;
    }

    private async Task SaveAppearance()
    {
        isSaving = true;
        await SettingsService.SaveAppearanceAsync(new AppearanceSettings(theme, fontSize, language, compactMode));
        statusMessage = "Appearance settings saved!";
        isSaving = false;
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        if (theme == "Dark") classes.Add("preview-dark");
        if (compactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private string GetPreviewFontStyle() => fontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };
}

