@code {
    private string displayName = "";
    private string email = "";
    private string bio = "";
    private string avatarUrl = "";

    private UserProfile? savedProfile;
    private bool isLoading = true;
    private bool isSaving;
    private string? statusMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfile();
    }

    private async Task LoadProfile()
    {
        isLoading = true;
        savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(savedProfile);
        isLoading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        displayName = profile.DisplayName;
        email = profile.Email;
        bio = profile.Bio;
        avatarUrl = profile.AvatarUrl;
    }

    private async Task SaveChanges()
    {
        isSaving = true;
        var updated = new UserProfile(displayName, email, avatarUrl, bio);
        await SettingsService.SaveProfileAsync(updated);
        savedProfile = updated;
        statusMessage = "Profile saved successfully!";
        isSaving = false;
    }

    private void DiscardChanges()
    {
        if (savedProfile is not null)
        {
            ApplyProfile(savedProfile);
        }
        statusMessage = null;
    }
}

