+    }
+    else
+    {
+        <ChangePasswordPanel OnChangePassword="HandleChangePassword" />
+
+        <div class="card mb-3">
+            <div class="card-body">
+                <div class="d-flex justify-content-between align-items-center">
+                    <div>
+                        <strong>Two-Factor Authentication</strong>
+                        <div class="text-muted small">Add an extra layer of security to your account</div>
+                    </div>
+                    <div class="d-flex align-items-center gap-2">
+                        <span class="badge @(twoFactorEnabled ? "bg-success" : "bg-secondary")">
+                            @(twoFactorEnabled ? "Enabled" : "Disabled")
+                        </span>
+                        <div class="form-check form-switch mb-0">
+                            <input class="form-check-input" type="checkbox" @bind="twoFactorEnabled" />
+                        </div>
+                    </div>
+                </div>
+                @if (lastPasswordChange.HasValue)
+                {
+                    <div class="text-muted small mt-2">
+                        Last password change: @lastPasswordChange.Value.ToString("MMMM d, yyyy")
+                    </div>
+                }
+            </div>
+        </div>
+
+        <div class="card mb-3">
+            <div class="card-header">Active Sessions</div>
+            <div class="card-body p-0">
+                <table class="table table-hover mb-0">
+                    <thead>
+                        <tr>
+                            <th>Device</th>
+                            <th>Location</th>
+                            <th>Last Active</th>
+                            <th></th>
+                        </tr>
+                    </thead>
+                    <tbody>
+                        @foreach (var session in sessions)
+                        {
+                            <tr>
+                                <td>@session.Device</td>
+                                <td>@session.Location</td>
+                                <td>@FormatLastActive(session.LastActive)</td>
+                                <td class="text-end">
+                                    @if (session != sessions.FirstOrDefault())
+                                    {
+                                        <button class="btn btn-outline-danger btn-sm"
+                                                @onclick="() => ShowRevokeDialog(session)">
+                                            Revoke
+                                        </button>
+                                    }
+                                    else
+                                    {
+                                        <span class="badge bg-info">Current</span>
+                                    }
+                                </td>
+                            </tr>
+                        }
+                    </tbody>
+                </table>
+            </div>
+        </div>
+
+        <RevokeSessionDialog Visible="showRevokeDialog"
+                             Device="@(sessionToRevoke?.Device ?? "")"
+                             Location="@(sessionToRevoke?.Location ?? "")"
+                             OnConfirm="ConfirmRevoke"
+                             OnCancel="CancelRevoke" />
+    }
+</div>
+
+@code {
+    private bool twoFactorEnabled;
+    private DateTime? lastPasswordChange;
+    private List<ActiveSession> sessions = new();
+
+    private bool isLoading = true;
+    private bool showRevokeDialog;
+    private ActiveSession? sessionToRevoke;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadSecurity();
+    }
+
+    private async Task LoadSecurity()
+    {
+        isLoading = true;
+        var settings = await SettingsService.GetSecuritySettingsAsync();
+        twoFactorEnabled = settings.TwoFactorEnabled;
+        lastPasswordChange = settings.LastPasswordChange;
+        sessions = settings.Sessions;
+        isLoading = false;
+    }
+
+    private async Task HandleChangePassword((string Current, string New) args)
+    {
+        await SettingsService.ChangePasswordAsync(args.Current, args.New);
+        var settings = await SettingsService.GetSecuritySettingsAsync();
+        lastPasswordChange = settings.LastPasswordChange;
+    }
+
+    private void ShowRevokeDialog(ActiveSession session)
+    {
+        sessionToRevoke = session;
+        showRevokeDialog = true;
+    }
+
+    private async Task ConfirmRevoke()
+    {
+        if (sessionToRevoke is not null)
+        {
+            await SettingsService.RevokeSessionAsync(sessionToRevoke.Id);
+            sessions.Remove(sessionToRevoke);
+        }
+        showRevokeDialog = false;
+        sessionToRevoke = null;
+    }
+
+    private void CancelRevoke()
+    {
+        showRevokeDialog = false;
+        sessionToRevoke = null;
+    }
+
+    private static string FormatLastActive(DateTime lastActive)
+    {
+        var diff = DateTime.UtcNow - lastActive;
+        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} minutes ago";
+        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours} hours ago";
+        return $"{(int)diff.TotalDays} days ago";
+    }
+}
+

